package com.forgeboard.document.application;
import static org.assertj.core.api.Assertions.assertThat; import static org.mockito.ArgumentMatchers.any; import static org.mockito.Mockito.*;
import java.time.*; import java.util.*; import org.junit.jupiter.api.*; import org.junit.jupiter.api.extension.ExtendWith; import org.mockito.*; import org.mockito.junit.jupiter.MockitoExtension;
import com.forgeboard.client.ClientDirectory; import com.forgeboard.document.domain.DocumentRequest; import com.forgeboard.document.persistence.DocumentRequestRepository; import com.forgeboard.identity.*; import com.forgeboard.identity.domain.MembershipRole;
@ExtendWith(MockitoExtension.class) class DocumentRequestServiceTest { @Mock DocumentRequestRepository requests; @Mock ClientDirectory clients; @Mock ActivityRecorder activity; DocumentRequestService service; SelectedTenant tenant; Instant now;
 @BeforeEach void setup(){now=Instant.parse("2026-07-13T09:00:00Z");tenant=new SelectedTenant(UUID.randomUUID(),UUID.randomUUID(),"owner@example.com",MembershipRole.OWNER);service=new DocumentRequestService(requests,clients,activity,Clock.fixed(now,ZoneOffset.UTC));}
 @Test void createsAndReceivesTenantScopedDocumentRequest(){UUID client=UUID.randomUUID();when(clients.exists(tenant.firmId(),client)).thenReturn(true);when(requests.save(any())).thenAnswer(i->i.getArgument(0));var created=service.create(tenant,new DocumentRequestInput(client,"Bank statements",null,LocalDate.of(2026,7,20)));when(requests.findByIdAndFirmId(created.id(),tenant.firmId())).thenReturn(Optional.of(new DocumentRequest(created.id(),tenant.firmId(),client,"Bank statements",null,LocalDate.of(2026,7,20),now)));var received=service.receive(tenant,created.id());assertThat(received.status().name()).isEqualTo("RECEIVED");verify(activity,times(2)).recordRestUserAction(any(),any(),any(),any(),any(),any());}
}
